def _residual_sse(ctx, y_values, columns):
    design_columns = [[1.0 for _ in y_values]]
    for values in columns:
        unique = []
        for value in values:
            if value not in unique:
                unique.append(value)
        for value in unique[1:]:
            design_columns.append([1.0 if current == value else 0.0 for current in values])
    design = ctx.np.asarray(design_columns, dtype=float).T
    y = ctx.np.asarray(y_values, dtype=float)
    fitted = ctx.np.linalg.lstsq(design, y, rcond=None)[0]
    residual = y - design.dot(fitted)
    return float(ctx.np.sum(residual * residual))


def run(ctx):
    items = ctx.dataset.included_items()
    rows = _collect_structure_rows(ctx, items)
    if not rows:
        return _structure_notice(ctx)
    combo_groups = {}
    for row in rows:
        key = (row["structure_main"], row["front"], row["back"], row["syl"], row["x"])
        combo_groups.setdefault(key, []).append(row["value"])
    combo_rows = []
    for key, values in combo_groups.items():
        structure, front, back, syl, x = key
        combo_rows.append({"structure": structure, "front": front, "back": back, "syl": syl, "x": x, "mean": _mean(values)})
    time_groups = {}
    for row in combo_rows:
        key = (row["structure"], row["syl"], row["x"])
        time_groups.setdefault(key, []).append(row)
    effect_rows = []
    for key, group_rows in time_groups.items():
        fronts = []
        backs = []
        y = []
        for row in group_rows:
            fronts.append(row["front"])
            backs.append(row["back"])
            y.append(row["mean"])
        if len(y) < 4 or len(set(fronts)) < 2 or len(set(backs)) < 2:
            continue
        arr = ctx.np.asarray(y, dtype=float)
        total = float(ctx.np.sum((arr - float(ctx.np.mean(arr))) ** 2))
        if total <= 0:
            continue
        front_sse = _residual_sse(ctx, y, [fronts])
        back_sse = _residual_sse(ctx, y, [backs])
        additive_sse = _residual_sse(ctx, y, [fronts, backs])
        front_part = max(0.0, 0.5 * ((total - front_sse) + (back_sse - additive_sse)))
        back_part = max(0.0, 0.5 * ((total - back_sse) + (front_sse - additive_sse)))
        interaction = max(0.0, additive_sse)
        denom = front_part + back_part + interaction
        if denom <= 0:
            continue
        structure, syl, x = key
        effect_rows.append({"structure": structure, "x": x, "front": front_part / denom, "back": back_part / denom, "interaction": interaction / denom})
    if not effect_rows:
        return _blank(ctx, "结构调类效应数据不足。\n每个结构和采样点至少需要多个前后调类组合才能估算占比。", title="结构效应数据不足")
    structures = sorted(list(set(row["structure"] for row in effect_rows)))
    fig, axes = ctx.plt.subplots(1, len(structures), figsize=(7.0 * len(structures), 5.0), sharey=True)
    axes_flat = ctx.np.atleast_1d(axes)
    for axis, structure in zip(axes_flat, structures):
        frame = [row for row in effect_rows if row["structure"] == structure]
        frame.sort(key=lambda row: row["x"])
        xs = [row["x"] for row in frame]
        axis.plot(xs, [row["front"] for row in frame], label="前字调类", linewidth=2.2)
        axis.plot(xs, [row["back"] for row in frame], label="后字调类", linewidth=2.2)
        axis.plot(xs, [row["interaction"] for row in frame], label="交互项/残差", linewidth=2.2)
        axis.axvline(100.0, color="#888888", linewidth=0.8)
        axis.set_xlim(0, 200)
        axis.set_ylim(0, 1)
        axis.set_xticks([5, 50, 95, 105, 150, 195])
        axis.set_xticklabels(["前5%", "前50%", "前95%", "后5%", "后50%", "后95%"])
        axis.set_title(str(structure))
        axis.set_xlabel("两字组归一化时间轴")
        axis.grid(alpha=0.25)
    axes_flat[0].set_ylabel("调类组合均值方差占比")
    axes_flat[-1].legend()
    fig.suptitle("不同结构类型的调类效应时间进程", fontsize=14, fontweight="bold")
    fig.tight_layout()
    ctx.log(f"绘制结构效应时间进程：{len(effect_rows)} 个时间点。")
    return ctx.figure(fig, filename="图08_不同结构类型调类效应时间进程.png", title="不同结构类型调类效应时间进程")
